/**
 * Background service worker — intentionally minimal for v0.
 *
 * Current responsibilities:
 *  - Open the side panel automatically when the extension action button is clicked.
 *
 * This is the right place to add in future:
 *  - Message relay (if content script needs to talk to side panel directly)
 *  - chrome.storage listeners (if state needs to persist across sessions)
 *  - WebSocket connection management (when adding realtime backend)
 *  - Alarm-based polling (if switching from push to pull data model)
 */

// Open the side panel on action click instead of showing a popup
chrome.sidePanel
  .setPanelBehavior({ openPanelOnActionClick: true })
  .catch(() => {
    // Older Chrome builds (< 116) don't support setPanelBehavior — safe to ignore
  });

chrome.runtime.onMessage.addListener((_message, _sender, _sendResponse) => {
  // Reserved for future message relay logic
});
